"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[715],{715:(n,i,e)=>{e.d(i,{Q:()=>u});let h=(n,i)=>i.map((i,e)=>{let[h,a,g,u,t]=i;return{sentence_id:"".concat(n,"-s").concat(e+1),chinese:h,pinyin:a,vietnamese:g,start:null!=u?u:6*e,end:null!=t?t:6*e+5.2,is_shadowing_enabled:!0}}),a=n=>n.map(n=>{let[i,e,h]=n;return{word:i,pinyin:e,vietnamese_meaning:h,audio_word:"",is_collectable:!0,typing_enabled:!0}}),g=n=>({...n,cover_image:"/covers/placeholder-listening.svg",audio_main:"/audio/main/daily-".concat(n.id.replace("ep-",""),"-main.mp3"),keywords:n.keywords.map((i,e)=>({...i,audio_word:"/audio/words/daily-".concat(n.id.replace("ep-",""),"-keyword-").concat(String(e+1).padStart(3,"0"),".mp3")})),chinese_text:n.sentences.map(n=>n.chinese).join(""),pinyin_text:n.sentences.map(n=>n.pinyin).join(" "),vietnamese_translation:n.sentences.map(n=>n.vietnamese).join(" "),shadowing_sentences:n.sentences.filter(n=>n.is_shadowing_enabled).map(n=>n.sentence_id),typing_words:n.keywords.filter(n=>n.typing_enabled).map(n=>n.word)}),u=[g({id:"ep-001",title:"为什么你学了 HSK 还是听不懂",category:"热点短文",is_featured_sample:!0,speaker:"林老师",sentences:h("ep-001",[["最近我有点儿不开心。","Zu\xecj\xecn wǒ yǒudiǎnr b\xf9 kāixīn.","Dạo n\xe0y t\xf4i hơi kh\xf4ng vui.",0,3.77],["怎么了？工作太忙吗？","Zěnme le? Gōngzu\xf2 t\xe0i m\xe1ng ma?","Sao vậy? C\xf4ng việc bận qu\xe1 \xe0?",3.77,8.34],["不是。我看到很多朋友都过得很好，可是我好像还没有什么变化。","B\xfa sh\xec. Wǒ k\xe0nd\xe0o hěn duō p\xe9ngyou dōu gu\xf2 de hěn hǎo, kěsh\xec wǒ hǎoxi\xe0ng h\xe1i m\xe9iyǒu sh\xe9nme bi\xe0nhu\xe0.","Kh\xf4ng phải. T\xf4i thấy nhiều bạn b\xe8 sống rất tốt, nhưng h\xecnh như t\xf4i vẫn chưa c\xf3 thay đổi g\xec.",8.34,18.38],["你是不是又在和别人比？","Nǐ sh\xec b\xfa sh\xec y\xf2u z\xe0i h\xe9 bi\xe9r\xe9n bǐ?","C\xf3 phải bạn lại đang so s\xe1nh m\xecnh với người kh\xe1c kh\xf4ng?",18.38,22.35],["可能是吧。看到他们越来越好，我就觉得自己进步得很慢。","Kěn\xe9ng sh\xec ba. K\xe0nd\xe0o tāmen yu\xe8 l\xe1i yu\xe8 hǎo, wǒ ji\xf9 ju\xe9de z\xecjǐ j\xecnb\xf9 de hěn m\xe0n.","C\xf3 lẽ vậy. Thấy họ ng\xe0y c\xe0ng tốt hơn, t\xf4i lại cảm thấy m\xecnh tiến bộ rất chậm.",22.35,30.65],["每个人的时间不一样。别人快，不代表你差。","Měi ge r\xe9n de sh\xedjiān b\xf9 y\xedy\xe0ng. Bi\xe9r\xe9n ku\xe0i, b\xf9 d\xe0ibiǎo nǐ ch\xe0.","Thời gian của mỗi người kh\xf4ng giống nhau. Người kh\xe1c nhanh kh\xf4ng c\xf3 nghĩa l\xe0 bạn k\xe9m.",30.65,39.12],["可是我还是会着急。","Kěsh\xec wǒ h\xe1ishi hu\xec zh\xe1oj\xed.","Nhưng t\xf4i vẫn sẽ sốt ruột.",39.12,42.47],["着急很正常。但你可以先做好今天的事。每天进步一点点，就已经很好了。","Zh\xe1oj\xed hěn zh\xe8ngch\xe1ng. D\xe0n nǐ kěyǐ xiān zu\xf2 hǎo jīntiān de sh\xec. Měitiān j\xecnb\xf9 y\xecdiǎndiǎn, ji\xf9 yǐjīng hěn hǎo le.","Sốt ruột l\xe0 b\xecnh thường. Nhưng bạn c\xf3 thể l\xe0m tốt việc h\xf4m nay trước. Mỗi ng\xe0y tiến bộ một ch\xfat đ\xe3 rất tốt rồi.",42.47,54.61],["你说得对。我不应该一直看别人。","Nǐ shuō de du\xec. Wǒ b\xf9 yīnggāi y\xeczh\xed k\xe0n bi\xe9r\xe9n.","Bạn n\xf3i đ\xfang. T\xf4i kh\xf4ng n\xean cứ nh\xecn người kh\xe1c m\xe3i.",54.61,60.75],["对。你要相信自己，也要给自己一点时间。","Du\xec. Nǐ y\xe0o xiāngx\xecn z\xecjǐ, yě y\xe0o gěi z\xecjǐ y\xecdiǎn sh\xedjiān.","Đ\xfang. Bạn phải tin bản th\xe2n, cũng phải cho bản th\xe2n th\xeam một ch\xfat thời gian.",60.75,68.44]]),keywords:a([["通过","tong guo","vượt qua"],["真实","zhen shi","thật, thực tế"],["紧张","jin zhang","căng thẳng"],["原因","yuan yin","nguy\xean nh\xe2n"],["努力","nu li","cố gắng"],["材料","cai liao","t\xe0i liệu"],["省略","sheng lue","lược bỏ"],["连读","lian du","nối \xe2m"],["表达","biao da","c\xe1ch diễn đạt"]]),is_free:!0,is_member_only:!1,member_cta:"想继续练真实语速？解锁更多 1 分钟精品听力。",created_at:"2026-06-16"}),g({id:"ep-002",title:"中国老板为什么这样说话",category:"职场 / 面试",is_featured_sample:!0,speaker:"周经理",sentences:h("ep-002",[["中国老板说“你再想想”，通常不是简单的建议。","Zhong guo lao ban shuo ni zai xiang xiang, tong chang bu shi jian dan de jian yi.","Sếp Trung Quốc n\xf3i 'bạn nghĩ th\xeam đi' thường kh\xf4ng chỉ l\xe0 lời khuy\xean đơn giản."],["这句话可能表示方案还不够成熟。","Zhe ju hua ke neng biao shi fang an hai bu gou cheng shu.","C\xe2u n\xe0y c\xf3 thể nghĩa l\xe0 phương \xe1n chưa đủ ch\xedn."],["如果老板说“辛苦了”，有时候是在提醒你继续跟进。","Ru guo lao ban shuo xin ku le, you shi hou shi zai ti xing ni ji xu gen jin.","Nếu sếp n\xf3i 'vất vả rồi', đ\xf4i khi l\xe0 nhắc bạn tiếp tục theo d\xf5i."],["听懂这些话背后的意思，开会和汇报都会顺利很多。","Ting dong zhe xie hua bei hou de yi si, kai hui he hui bao dou hui shun li hen duo.","Hiểu \xfd ph\xeda sau những c\xe2u n\xe0y th\xec họp v\xe0 b\xe1o c\xe1o đều thuận lợi hơn nhiều."]]),keywords:a([["老板","lao ban","sếp"],["通常","tong chang","thường"],["建议","jian yi","đề nghị"],["方案","fang an","phương \xe1n"],["成熟","cheng shu","ch\xedn chắn"],["辛苦了","xin ku le","vất vả rồi"],["提醒","ti xing","nhắc nhở"],["跟进","gen jin","theo d\xf5i tiếp"],["顺利","shun li","thuận lợi"],["汇报","hui bao","b\xe1o c\xe1o"]]),is_free:!0,is_member_only:!1,member_cta:"继续听懂职场潜台词，解锁更多老板常用表达。",created_at:"2026-06-16"}),g({id:"ep-003",title:"面试时怎么介绍自己",category:"职场 / 面试",is_featured_sample:!0,speaker:"王老师",sentences:h("ep-003",[["面试介绍自己，不要只说名字和学校。","Mian shi jie shao zi ji, bu yao zhi shuo ming zi he xue xiao.","Khi phỏng vấn giới thiệu bản th\xe2n, đừng chỉ n\xf3i t\xean v\xe0 trường."],["你可以先说专业，再说一段相关经历。","Ni ke yi xian shuo zhuan ye, zai shuo yi duan xiang guan jing li.","Bạn c\xf3 thể n\xf3i chuy\xean ng\xe0nh trước, rồi n\xf3i một kinh nghiệm li\xean quan."],["最后说明你为什么适合这个岗位。","Zui hou shuo ming ni wei shen me shi he zhe ge gang wei.","Cuối c\xf9ng giải th\xedch v\xec sao bạn ph\xf9 hợp với vị tr\xed n\xe0y."],["表达要自然，语速不用太快，不要像背课文。","Biao da yao zi ran, yu su bu yong tai kuai, bu yao xiang bei ke wen.","C\xe1ch n\xf3i cần tự nhi\xean, tốc độ kh\xf4ng cần qu\xe1 nhanh, đừng giống như đọc thuộc b\xe0i."]]),keywords:a([["面试","mian shi","phỏng vấn"],["介绍","jie shao","giới thiệu"],["专业","zhuan ye","chuy\xean ng\xe0nh"],["相关","xiang guan","li\xean quan"],["经历","jing li","kinh nghiệm"],["说明","shuo ming","giải th\xedch"],["适合","shi he","ph\xf9 hợp"],["岗位","gang wei","vị tr\xed c\xf4ng việc"],["自然","zi ran","tự nhi\xean"],["语速","yu su","tốc độ n\xf3i"]]),is_free:!0,is_member_only:!1,member_cta:"准备中文面试？继续解锁更多自然回答模板。",created_at:"2026-06-16"}),g({id:"ep-004",title:"今天大家都在聊的加班文化",category:"热点短文",speaker:"小陈",sentences:h("ep-004",[["最近，加班文化又成了热门话题。","Zui jin, jia ban wen hua you cheng le re men hua ti.","Gần đ\xe2y, văn h\xf3a tăng ca lại th\xe0nh chủ đề n\xf3ng."],["有些年轻人希望工作和生活保持平衡。","You xie nian qing ren xi wang gong zuo he sheng huo bao chi ping heng.","Một số người trẻ muốn giữ c\xe2n bằng giữa c\xf4ng việc v\xe0 cuộc sống."],["也有人觉得，刚开始工作应该多学习。","Ye you ren jue de, gang kai shi gong zuo ying gai duo xue xi.","Cũng c\xf3 người cho rằng mới đi l\xe0m n\xean học nhiều hơn."],["不同公司有不同节奏，听懂讨论很重要。","Bu tong gong si you bu tong jie zou, ting dong tao lun hen zhong yao.","Mỗi c\xf4ng ty c\xf3 nhịp kh\xe1c nhau, hiểu cuộc thảo luận rất quan trọng."]]),keywords:a([["最近","zui jin","gần đ\xe2y"],["加班","jia ban","tăng ca"],["文化","wen hua","văn h\xf3a"],["热门","re men","n\xf3ng, phổ biến"],["话题","hua ti","chủ đề"],["平衡","ping heng","c\xe2n bằng"],["节奏","jie zou","nhịp độ"],["讨论","tao lun","thảo luận"]]),is_free:!1,is_member_only:!0,member_cta:"会员可继续收听热点职场话题。",created_at:"2026-06-16"}),g({id:"ep-005",title:"地铁里听到的一段对话",category:"真实对话",speaker:"双人对话",sentences:h("ep-005",[["你到哪站下车？","Ni dao na zhan xia che?","Bạn xuống ga n\xe0o?"],["我到人民广场，应该还有三站。","Wo dao Ren min Guang chang, ying gai hai you san zhan.","T\xf4i đến Quảng trường Nh\xe2n D\xe2n, chắc c\xf2n ba ga."],["那我们差不多，我在下一站换线。","Na wo men cha bu duo, wo zai xia yi zhan huan xian.","Vậy cũng gần giống nhau, t\xf4i đổi tuyến ở ga sau."],["下班时间人太多了。","Xia ban shi jian ren tai duo le.","Giờ tan l\xe0m đ\xf4ng người qu\xe1."]]),keywords:a([["地铁","di tie","t\xe0u điện ngầm"],["下车","xia che","xuống xe"],["广场","guang chang","quảng trường"],["应该","ying gai","chắc l\xe0"],["差不多","cha bu duo","gần như"],["换线","huan xian","đổi tuyến"],["下班","xia ban","tan l\xe0m"],["时间","shi jian","thời gian"]]),is_free:!0,is_member_only:!1,member_cta:"解锁更多真实生活对话。",created_at:"2026-06-16"}),g({id:"ep-006",title:"朋友约饭时怎么说",category:"真实对话",speaker:"双人对话",sentences:h("ep-006",[["晚上有空吗？一起吃个饭吧。","Wan shang you kong ma? Yi qi chi ge fan ba.","Tối rảnh kh\xf4ng? Đi ăn c\xf9ng nh\xe9."],["可以啊，不过我六点半以后才有时间。","Ke yi a, bu guo wo liu dian ban yi hou cai you shi jian.","Được, nhưng sau s\xe1u rưỡi t\xf4i mới c\xf3 thời gian."],["那我们七点在公司楼下见。","Na wo men qi dian zai gong si lou xia jian.","Vậy bảy giờ gặp dưới c\xf4ng ty."],["好，我想吃点清淡的。","Hao, wo xiang chi dian qing dan de.","Được, t\xf4i muốn ăn m\xf3n nhẹ."]]),keywords:a([["有空","you kong","rảnh"],["一起","yi qi","c\xf9ng nhau"],["不过","bu guo","nhưng m\xe0"],["以后","yi hou","sau đ\xf3"],["公司","gong si","c\xf4ng ty"],["楼下","lou xia","dưới lầu"],["清淡","qing dan","thanh đạm"],["见","jian","gặp"]]),is_free:!1,is_member_only:!0,member_cta:"会员可继续学习自然邀约表达。",created_at:"2026-06-16"}),g({id:"ep-007",title:"同事之间的早上问候",category:"真实对话",speaker:"办公室对话",sentences:h("ep-007",[["早，昨天那个文件你看了吗？","Zao, zuo tian na ge wen jian ni kan le ma?","Ch\xe0o buổi s\xe1ng, h\xf4m qua bạn xem t\xe0i liệu đ\xf3 chưa?"],["看了，我觉得数据还需要确认一下。","Kan le, wo jue de shu ju hai xu yao que ren yi xia.","Xem rồi, t\xf4i thấy dữ liệu vẫn cần x\xe1c nhận th\xeam."],["好，那上午开会前我们再对一下。","Hao, na shang wu kai hui qian wo men zai dui yi xia.","Được, trước cuộc họp buổi s\xe1ng m\xecnh đối chiếu lại."],["没问题，我九点半到会议室。","Mei wen ti, wo jiu dian ban dao hui yi shi.","Kh\xf4ng vấn đề, ch\xedn rưỡi t\xf4i đến ph\xf2ng họp."]]),keywords:a([["文件","wen jian","t\xe0i liệu"],["数据","shu ju","dữ liệu"],["需要","xu yao","cần"],["确认","que ren","x\xe1c nhận"],["上午","shang wu","buổi s\xe1ng"],["开会","kai hui","họp"],["会议室","hui yi shi","ph\xf2ng họp"],["没问题","mei wen ti","kh\xf4ng vấn đề"]]),is_free:!1,is_member_only:!0,member_cta:"开通会员，继续练办公室对话。",created_at:"2026-06-16"}),g({id:"ep-008",title:"短视频为什么让人停不下来",category:"热点短文",speaker:"阿明",sentences:h("ep-008",[["很多人刷短视频，一刷就是一个小时。","Hen duo ren shua duan shi pin, yi shua jiu shi yi ge xiao shi.","Nhiều người lướt video ngắn l\xe0 mất cả tiếng."],["短视频内容短，反馈也很快。","Duan shi pin nei rong duan, fan kui ye hen kuai.","Video ngắn c\xf3 nội dung ngắn v\xe0 phản hồi rất nhanh."],["所以大脑会觉得很轻松。","Suo yi da nao hui jue de hen qing song.","V\xec vậy n\xe3o cảm thấy rất thoải m\xe1i."],["学习中文时，也可以用短内容建立习惯。","Xue xi Zhong wen shi, ye ke yi yong duan nei rong jian li xi guan.","Khi học tiếng Trung, cũng c\xf3 thể d\xf9ng nội dung ngắn để x\xe2y th\xf3i quen."]]),keywords:a([["短视频","duan shi pin","video ngắn"],["内容","nei rong","nội dung"],["反馈","fan kui","phản hồi"],["大脑","da nao","n\xe3o bộ"],["轻松","qing song","thoải m\xe1i"],["建立","jian li","x\xe2y dựng"],["习惯","xi guan","th\xf3i quen"],["小时","xiao shi","giờ"]]),is_free:!0,is_member_only:!1,member_cta:"会员可继续解锁热点听力。",created_at:"2026-06-16"}),g({id:"ep-009",title:"入职第一天应该注意什么",category:"职场 / 面试",speaker:"刘主管",sentences:h("ep-009",[["入职第一天，先记住同事的名字。","Ru zhi di yi tian, xian ji zhu tong shi de ming zi.","Ng\xe0y đầu nhận việc, trước ti\xean h\xe3y nhớ t\xean đồng nghiệp."],["不懂的问题可以问，但要先自己看一遍资料。","Bu dong de wen ti ke yi wen, dan yao xian zi ji kan yi bian zi liao.","C\xe2u hỏi kh\xf4ng hiểu c\xf3 thể hỏi, nhưng h\xe3y tự xem t\xe0i liệu trước."],["和主管确认工作优先级也很重要。","He zhu guan que ren gong zuo you xian ji ye hen zhong yao.","X\xe1c nhận mức ưu ti\xean c\xf4ng việc với quản l\xfd cũng rất quan trọng."],["这样别人会觉得你很靠谱。","Zhe yang bie ren hui jue de ni hen kao pu.","Như vậy người kh\xe1c sẽ thấy bạn đ\xe1ng tin cậy."]]),keywords:a([["入职","ru zhi","nhận việc"],["记住","ji zhu","ghi nhớ"],["同事","tong shi","đồng nghiệp"],["资料","zi liao","t\xe0i liệu"],["主管","zhu guan","quản l\xfd"],["优先级","you xian ji","mức ưu ti\xean"],["重要","zhong yao","quan trọng"],["靠谱","kao pu","đ\xe1ng tin"]]),is_free:!1,is_member_only:!0,member_cta:"会员可学习更多入职场景中文。",created_at:"2026-06-16"}),g({id:"ep-010",title:"为什么越来越多人学中文",category:"热点短文",speaker:"小雨",sentences:h("ep-010",[["现在，越来越多越南学生开始学中文。","Xian zai, yue lai yue duo Yue nan xue sheng kai shi xue Zhong wen.","Hiện nay, ng\xe0y c\xe0ng nhiều học sinh Việt Nam bắt đầu học tiếng Trung."],["有人是为了找工作，有人是为了做生意。","You ren shi wei le zhao gong zuo, you ren shi wei le zuo sheng yi.","C\xf3 người để t\xecm việc, c\xf3 người để kinh doanh."],["但是只会考试还不够，还要听懂真实表达。","Dan shi zhi hui kao shi hai bu gou, hai yao ting dong zhen shi biao da.","Nhưng chỉ biết thi l\xe0 chưa đủ, c\xf2n phải nghe hiểu c\xe1ch n\xf3i thật."],["每天一点点，进步会更稳定。","Mei tian yi dian dian, jin bu hui geng wen ding.","Mỗi ng\xe0y một ch\xfat, tiến bộ sẽ ổn định hơn."]]),keywords:a([["越南","Yue nan","Việt Nam"],["开始","kai shi","bắt đầu"],["为了","wei le","để"],["找工作","zhao gong zuo","t\xecm việc"],["做生意","zuo sheng yi","kinh doanh"],["考试","kao shi","thi cử"],["进步","jin bu","tiến bộ"],["稳定","wen ding","ổn định"]]),is_free:!0,is_member_only:!1,member_cta:"继续每天练 1 分钟真实中文。",created_at:"2026-06-16"})]}}]);